import './Expenses.css';
import ExpenseItem from './ExpenseItem';
import Card from '../UI/Card';


function Expenses(props){
    const expenseList = props.expenseList;
    return (
        <div>
            <Card className = 'expenses'>
                {props.expenseList.map((expenseItem) => {return (<ExpenseItem date = {expenseItem.date} title = {expenseItem.title} amount = {expenseItem.amount}></ExpenseItem>);})}
                {[<h1>Hi1</h1>, <h2>hi2</h2>]}
            </Card>
        </div>
    )
}
export default Expenses;
